  ('disabled-6f0ba476-moex-00211', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '在討論租稅對代表性個人勞動供給影響時，當休閒為正常財，且所得效果大 於替代效果時，比例薪資所得稅稅率降低對代表性個人勞動供給的影響，下 列敘述何者正確？', '["供給量減少", "供給量增加", "供給減少", "供給增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00212', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '非線型所得稅稅率結構（anonlinearincometaxstructure）提供無所得者一筆 定額的補助，下列那一項不符合該效率稅率結構的基本原則？', '["課徵高平均稅率結合低邊際稅率", "讓少數民眾適用高邊際稅率", "對少扭曲損害者（低所得者）課徵較高的邊際稅率", "對高所得者課徵較低的平均稅率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00213', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '假設消費為正常財，當其他條件不變時，關於對儲蓄者課徵利息所得稅所產 生經濟效果，下列敘述何者正確？', '["替代效果減少儲蓄，所得效果減少當期消費", "替代效果減少儲蓄，所得效果增加當期消費", "替代效果增加儲蓄，所得效果減少當期消費", "替代效果增加儲蓄，所得效果增加當期消費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00214', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '資本增益通常是多年累積而成，若於實現時一次課徵，適用較高的累進稅率， 往往會造成稅負集中現象，影響資產持有人出售資產的意願。關於資本利得 課稅可能產生的問題，與下列那些效果最為相關？', '["所得效果與替代效果", "位移效果與集中效果", "連鎖效果與嵌入效果", "集遽效果與閉鎖效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00215', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '如果政府規定納稅義務人將部分薪資存入退休帳戶的金額可在當期所得扣 除，於退休提領本金與利息時一併課稅。此一制度相當於對何種所得免稅？', '["薪資所得", "退職所得", "資產利得", "利息所得"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
