  ('disabled-6f0ba476-moex-00217', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '對企業匯回境外所得應否課稅之爭議，與下列那一項財政概念的內涵有關？', '["中央與地方稅源之劃分", "財政集權與分權之差異", "課稅屬人與屬地主義之討論", "所得稅與消費稅之優劣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00218', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '在一般均衡模型下，若公司所得稅視為對資本課稅，租稅負擔為何？', '["不可能由勞動者負擔", "一定全部由資本所有者負擔", "有可能由勞動者負擔", "一定全部由勞動者負擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "340fd4aa51e1", "answer_pdf_sha1": "2b16893eca27", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
